        ngx.header["Content-Type"] = "application/json"
        ngx.say('{"error": "Unknown user role"}')
        return ngx.exit(ngx.HTTP_FORBIDDEN)
    end

    -- Normalize URI: remove trailing slashes, collapse double slashes, decode and re-check
    -- This prevents bypass via paths like "/admin/../admin" or "/admin/"
    local normalized_uri = _M.normalize_uri(uri)

