function _M.normalize_uri(uri)
    if not uri or uri == "" then
        return "/"
    end

    -- Decode percent-encoded characters to prevent bypass via encoding
    -- e.g., %2Fadmin or %2fadmin
    local decoded = ngx.unescape_uri(uri)

    -- Remove null bytes to prevent null byte injection
    decoded = string.gsub(decoded, "%z", "")

    -- Collapse multiple consecutive slashes into one
    decoded = string.gsub(decoded, "/+", "/")

    -- Remove trailing slash (unless it's the root "/")
    if #decoded > 1 and string.sub(decoded, -1) == "/" then
        decoded = string.sub(decoded, 1, -2)
    end

    -- Resolve path traversal sequences (e.g., /../, /./)
    local segments = {}
    for segment in string.gmatch(decoded, "[^/]+") do
        if segment == ".." then
            -- Go up one level
            if #segments > 0 then
                table.remove(segments)
            end
        elseif segment ~= "." then
            table.insert(segments, segment)
        end
    end

    local normalized = "/" .. table.concat(segments, "/")

    -- Double-check: decode again and compare to detect double encoding attacks
    local double_decoded = ngx.unescape_uri(normalized)
    if double_decoded ~= normalized then
        -- Double encoding detected, use the fully decoded version
        -- Re-normalize the double-decoded version
        double_decoded = string.gsub(double_decoded, "%z", "")
        double_decoded = string.gsub(double_decoded, "/+", "/")
        if #double_decoded > 1 and string.sub(double_decoded, -1) == "/" then
            double_decoded = string.sub(double_decoded, 1, -2)
        end
        normalized = double_decoded
    end

    return normalized
end

