-- Rate limiting helper to prevent brute force on auth
function _M.check_rate_limit(identifier)
    local rate_limit = ngx.shared.rate_limit
    if not rate_limit then
        return true -- If rate limiting not configured, allow
    end

    local key = "rate:" .. identifier
    local count, err = rate_limit:incr(key, 1, 0, 60) -- 60 second window

    if not count then
        ngx.log(ngx.ERR, "Rate limit error: ", err)
        return true
    end

    -- Allow max 100 requests per minute per identifier
    if count > 100 then
        ngx.status = 429
        ngx.header["Content-Type"] = "application/json"
        ngx.header["Retry-After"] = "60"
        ngx.say('{"error": "Rate limit exceeded. Try again later."}')
        ngx.exit(429)
        return false
    end

    return true
end

